  json: {
    SUPABASE_URL: 'https://zcmqcosuvjndgcwylzna.supabase.co',
    SUPABASE_KEY: 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InpjbXFjb3N1dmpuZGdjd3lsem5hIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MzMxNTcwOCwiZXhwIjoyMDg4ODkxNzA4fQ.lgJ_VxIBAZMmTtjo3L4vUwsIGRD_glaYYsdhHkuUTHM',
    EVOLUTION_URL: 'https://evo.vortekai.es',
    EVOLUTION_INSTANCE: 'Ventas vortek',
    WHATSAPP_NUMBER: '34628706539',
  }
}];

const config = $input.first().json;
const now = new Date();
const madridTime = new Date(now.toLocaleString('en-US', { timeZone: 'Europe/Madrid' }));
const todayStr = madridTime.toISOString().split('T')[0];
const startISO = todayStr + 'T00:00:00Z';
const endISO = todayStr + 'T23:59:59Z';
const headers = { 'apikey': config.SUPABASE_KEY, 'Authorization': `Bearer ${config.SUPABASE_KEY}` };

// Proyectos hoy
const projResp = await fetch(
  `${config.SUPABASE_URL}/rest/v1/workana_projects?select=id,status,relevance_score&created_at=gte.${startISO}&created_at=lte.${endISO}`,
  { headers }
);
const projects = await projResp.json();

// Propuestas hoy
const propResp = await fetch(
  `${config.SUPABASE_URL}/rest/v1/workana_proposals?select=id,budget_suggested&created_at=gte.${startISO}&created_at=lte.${endISO}`,
  { headers }
);
const proposals = await propResp.json();

// Errores hoy
const errResp = await fetch(
  `${config.SUPABASE_URL}/rest/v1/workana_logs?select=id&created_at=gte.${startISO}&created_at=lte.${endISO}&success=eq.false`,
  { headers }
);
const errors = await errResp.json();

// Cuota semanal
const startOfWeek = new Date(madridTime);
const dayOfWeek = startOfWeek.getDay() === 0 ? 7 : startOfWeek.getDay();
startOfWeek.setDate(startOfWeek.getDate() - (dayOfWeek - 1));
startOfWeek.setHours(0, 0, 0, 0);
const weekResp = await fetch(
  `${config.SUPABASE_URL}/rest/v1/workana_proposals?select=id&created_at=gte.${startOfWeek.toISOString()}`,
  { headers }
);
const weekProposals = await weekResp.json();

// Retry queue pendientes
let retryPending = 0;
try {
  const retryResp = await fetch(
    `${config.SUPABASE_URL}/rest/v1/workana_retry_queue?select=id&status=eq.pending`,
    { headers }
  );
  const retryItems = await retryResp.json();
  retryPending = Array.isArray(retryItems) ? retryItems.length : 0;
} catch (e) { /* tabla puede no existir aún */ }

const totalProjects = Array.isArray(projects) ? projects.length : 0;
const totalProposals = Array.isArray(proposals) ? proposals.length : 0;
const totalErrors = Array.isArray(errors) ? errors.length : 0;
const weekTotal = Array.isArray(weekProposals) ? weekProposals.length : 0;
const sent = Array.isArray(projects) ? projects.filter(p => p.status === 'sent').length : 0;
const skipped = Array.isArray(projects) ? projects.filter(p => p.status === 'skipped').length : 0;
const avgRelevance = totalProjects > 0
  ? Math.round(projects.reduce((sum, p) => sum + (p.relevance_score || 0), 0) / totalProjects)
  : 0;
const totalBudget = Array.isArray(proposals)
  ? proposals.reduce((sum, p) => sum + (p.budget_suggested || 0), 0)
  : 0;

const relevanceBar = '█'.repeat(Math.floor(avgRelevance / 10)) + '░'.repeat(10 - Math.floor(avgRelevance / 10));

const msg = `📊 *RESUMEN DIARIO - ${todayStr}*

📋 Proyectos analizados: ${totalProjects}
✅ Propuestas generadas: ${totalProposals}
📨 Enviadas auto: ${sent}
⏭️ Descartados: ${skipped}
❌ Errores: ${totalErrors}
🔄 En cola de reintento: ${retryPending}
🎯 Relevancia media: ${relevanceBar} ${avgRelevance}/100
💶 Valor total propuestas: €${totalBudget}

📅 *Cuota semanal:* ${weekTotal} propuestas

${totalErrors > 3 ? '⚠️ Demasiados errores hoy. Revisa los logs.' : '✅ Sistema operando correctamente.'}`;

return [{
  json: {
    ...config,
    message: msg,
  }
}];
